var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제 이름을 알고 있다는 건…….","JPN":"私の名前を知っているということは……","ENG":"So you know my name...","TWN":"你知道我的名字……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 당신도 그 사람들과 같은 곳에서 온 이방인인 모양이네요.","JPN":"そうですか、あなたもあの人たちと同じ世界から来た異邦人なのですね。","ENG":"I see. Then you must be an outsider from the same place as those people.","TWN":"原來如此。看來你也和那些人一樣，是來自同一個地方的異鄉人。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 사람들? 아, 미나 양을 말씀하는 건가요?","JPN":"あの人たち？　ああ、ミナさんのことですか？","ENG":"Those people? Ah, you mean Mina?","TWN":"那些人？啊，你是指米娜嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 미나 양과 같은 세계에서 온 것은 맞지만, 같은 목적으로 온 건 아닙니다.","JPN":"はは、ミナさんと同じ世界から来たのは確かですが、目的は違います。","ENG":"Haha, it's true that we're from the same world, but we didn't come here for the same reason.","TWN":"哈哈，我們的確來自同一個世界，但我們的目的並不相同。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"제 목적은 <color=#ffd34c>당신</color>이거든요.","JPN":"僕の目的は<color=#ffd34c>あなた</color>ですから。","ENG":"My objective is <color=#ffd34c>you</color>.","TWN":"我的目的，是<color=#ffd34c>你</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신의 목적이 저라고요?","JPN":"あなたの目的が私？","ENG":"I'm your objective?","TWN":"你的目的是我？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네, 이런저런 사정이 있어서요.","JPN":"ええ、色々事情がありましてね。","ENG":"Yes. There are various circumstances.","TWN":"對，因為一些原因。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"말로 설명하는 것보다는 이쪽이 빠르겠네요.","JPN":"言葉で説明するよりは、こっちのほうが手っ取り早いでしょう。","ENG":"It would be faster to show you than to explain it.","TWN":"與其用言語說明，不如直接讓你看看吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>테라브레인 단말 접속 확인.</color>","JPN":"<color=#ffd34c>テラブレイン端末接続確認。</color>","ENG":"<color=#ffd34c>Terrabrain terminal connection confirmed.</color>","TWN":"<color=#ffd34c>確認連接特拉大腦終端。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L15_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>경고. 단말의 해치를 개방하기 위해서는 2급 관리자 이상의 권한이 필요합니다.</color>","JPN":"<color=#ffd34c>警告。端末のハッチを開放するためには2級管理者以上の権限が必要です。</color>","ENG":"<color=#ffd34c>Warning. Class 2 Administrator authorization or higher is required to open the terminal hatch.</color>","TWN":"<color=#ffd34c>警告。開啟終端艙口需要二級管理者以上權限。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코드를 입력해주십시오.</color>","JPN":"<color=#ffd34c>コードを入力してください。</color>","ENG":"<color=#ffd34c>Please enter the code.</color>","TWN":"<color=#ffd34c>請輸入代碼。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"검은 상자가 말을 하잖아? 이게 대체 뭐죠?","JPN":"黒い箱が言葉を？　これはいったい何なのですか？","ENG":"The black box is talking? What is this thing?","TWN":"黑色箱子在說話？這到底是什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그런가. 리하르트의 시니어 코드로 단말을 잠가 둔 모양이군.","JPN":"そうか。リヒャルトのシニアコードで端末をロックしていたか。","ENG":"I see. It seems the terminal was locked with Richard's Senior Code.","TWN":"原來如此，用理查的資深代碼把終端鎖起來了啊。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"훗, 과연 마지막까지 용의주도하네. 하지만…….","JPN":"ふっ、最後まで用意周到だ。しかし……","ENG":"Heh, meticulous to the very end. But...","TWN":"呵，果然到最後一刻都很謹慎。不過……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>2급 관리자 나유빈 확인.</color>","JPN":"<color=#ffd34c>2級管理者イチノセ・カオルを確認。</color>","ENG":"<color=#ffd34c>Class 2 Administrator Na Yubin, confirmed.</color>","TWN":"<color=#ffd34c>確認二級管理者羅瑜斌。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L24_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>해치를 개방합니다.</color>","JPN":"<color=#ffd34c>ハッチを開放します。</color>","ENG":"<color=#ffd34c>Opening hatch.</color>","TWN":"<color=#ffd34c>艙口開啟。</color>"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"상자가 열렸어……?","JPN":"箱が開いた……？","ENG":"It opened...?","TWN":"箱子打開了……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 설마 이게 <color=#ffd34c>다른 세계로 통하는 문</color>인가요……?","JPN":"では、まさかこれが<color=#ffd34c>別の世界に通じる扉</color>ですか……？","ENG":"Then... could this be a <color=#ffd34c>door to another world</color>...?","TWN":"那麼，難道這真的是通往<color=#ffd34c>其他世界的門</color>……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다른 세계로 통하는 문? 그게 무슨 말이죠?","JPN":"別の世界に通じる扉？　何を言っているんですか？","ENG":"A door to another world? What do you mean?","TWN":"通往其他世界的門？你這是什麼意思？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이야말로 무슨 말이죠?","JPN":"あなたこそ、何を言っているんですか？","ENG":"What do you mean, what do I mean?","TWN":"是我要問你這句話才對吧？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인은 이 유적이 다른 세계로 통하는 문이라고 했는데……?","JPN":"アバーラインは、この遺跡が別の世界に通じる扉だと言っていたのですが……","ENG":"Abberline said this ruin was a door to another world...","TWN":"艾伯林說這座遺跡是通往其他世界的門啊……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히… 세계를 넘나든다는 게 틀린 말은 아니지만, 이건 문 같은 게 아닙니다.","JPN":"確かに……世界を行き来するという点では概ね間違っていませんが、これは扉のようなものではありません。","ENG":"Well... it's not wrong to say it crosses worlds, but this isn't a door.","TWN":"確實……說它能跨越世界並不算錯，但這並不是什麼門。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 단말기는 일종의 나침반 겉은 거죠. 함선을 안내하는.","JPN":"この端末は一種の羅針盤です。艦船を導くためのね。","ENG":"This terminal is more like a kind of compass. One that guides a ship.","TWN":"這台終端，更像是一種用來引導艦船的指南針。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"함선? 그럼, 이 유적이 배의 일부였다는 뜻인가요?","JPN":"艦船？　ではこの遺跡は船の一部だったということですか？","ENG":"A ship? Then does that mean this ruin was part of a ship?","TWN":"艦船？所以這座遺跡其實是船的一部分嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 이해가 빠르시네요.","JPN":"はは、理解が早いですね。","ENG":"Haha, you catch on quickly.","TWN":"哈哈，你理解得真快。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래요, 우리 세계는 이런 좌초된 함선을 <color=#ffd34c>로스트쉽</color>이라고 부릅니다.","JPN":"そう。僕たちの世界ではこのような座礁した艦船のことを<color=#ffd34c>ロストシップ</color>と呼んでいます。","ENG":"Yes. In our world, we call wrecked ships like this a <color=#ffd34c>Lost Ship</color>.","TWN":"沒錯。在我們的世界，這種擱淺的艦船被稱為<color=#ffd34c>失落之船</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 이 로스트쉽과 테라브레인은 관리자님께서 이 세계에 남겨둔 유산.","JPN":"おそらくこのロストシップとテラブレインは、管理者さんがこの世界に遺した遺産。","ENG":"This Lost Ship and the Terrabrain are probably legacies the Administrator left behind in this world.","TWN":"而這艘失落之船還有特拉大腦，大概就是管理者留在這個世界的遺產吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 당신에게 있어서, 이곳은…….","JPN":"そしてあなたにとって、ここは……","ENG":"And for you, this place is...","TWN":"而對你來說，這裡就是……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모든 각본이 시작된 곳</color>이라고도 할 수 있겠죠.","JPN":"<color=#ffd34c>すべての脚本が始まった場所</color>と言えるでしょう。","ENG":"It could be called <color=#ffd34c>where all scripts began</color>.","TWN":"<color=#ffd34c>所有劇本開始的地方</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"모든 각본이 시작된 곳……?","JPN":"すべての脚本が始まった場所……？","ENG":"Where all scripts began...?","TWN":"所有劇本開始的地方……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"나무를 숨기려면, 숲에 숨긴다라… 역시 스완은 뛰어난 각본가네요.","JPN":"木を隠すなら森の中……スワンはやはり優れた脚本家です。","ENG":"Hide a tree in the forest... as expected of Swan, a brilliant scriptwriter.","TWN":"所謂要藏起一棵樹，就藏進森林中……史旺，你果然是個出色的編劇。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"타기리온의 클리파에 귀속된 고향 세계, 그것도 테라브레인이 있는 이 장소라면…….","JPN":"タギリオンのクリファに帰属する故郷の世界、しかもテラブレインがあるここは……","ENG":"If it's your home world bound to Thagirion's Qlipha, and a place with a Terrabrain...","TWN":"在歸屬於塔基里翁逆卡巴拉故鄉的世界，而且還是擁有特拉大腦的這個地方……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그녀에게 들키지 않게, <color=#ffd34c>퍼즐 조각</color>을 숨겨 놓기에는 최적의 장소로군요.","JPN":"彼女にバレず<color=#ffd34c>パズルのピース</color>を隠すにはうってつけの場所です。","ENG":"It's the perfect place to hide a <color=#ffd34c>piece of the puzzle</color> without her noticing.","TWN":"要不被她察覺，藏起<color=#ffd34c>拼圖碎片</color>，這裡確實是最合適的地點。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"클리파? 테라브레인? 퍼즐 조각? 아까부터 무슨 말씀을 하시는 거죠?","JPN":"クリファ？　テラブレイン？　パズルのピース？　先程から何の話ですか？","ENG":"Qlipha? Terrabrain? Piece of the puzzle? What are you talking about?","TWN":"逆卡巴拉？特拉大腦？拼圖碎片？你從剛才開始到底在說什麼？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"말을 어렵게 빙빙 돌려 말하는 건, 제가 아는 누구랑 똑같군요.","JPN":"話が回りくどいのは、私の知り合いとそっくりですね。","ENG":"The way you keep circling around with complicated explanations is just like someone I know.","TWN":"說話拐彎抹角，這點簡直和我認識的某個人一模一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 제가 조금 불친절했나요?","JPN":"はは、僕の説明が少し不親切でしたか？","ENG":"Haha, was I being a bit unkind?","TWN":"哈哈，是我說得太難懂了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이곳에 발을 들였을 때, 당신은 어떤 위화감을 느꼈을 겁니다.","JPN":"ここに足を踏み入れた時、あなたは何らかの違和感を覚えたはずです。","ENG":"When you stepped into this place, you must have felt a sense of unease.","TWN":"當你踏進這裡時，應該會感受到某種違和感吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"위화감? 그러고 보니…….","JPN":"違和感？　言われてみれば……","ENG":"Unease? Now that you mention it...","TWN":"違和感？你這麼一說……"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그건 당신이 이곳에 와본 적이 있다는 뜻.","JPN":"それはあなたがここに来たことがあるという証拠です。","ENG":"That means you've been here before.","TWN":"那代表你曾經來過這裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"엄밀히 말하면, 그건 당신이 아니라 또 다른 당신이겠지만…….","JPN":"厳密には、あなたではなくもう一人のあなたでしょうけど……","ENG":"Strictly speaking, it wasn't you, but another you...","TWN":"嚴格來說，來過的不是現在的你，而是另一個你……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"적어도 이 클리파 차원은 당신<color=#ffd34c>들</color>의 동일성을 인정하고 있어요.","JPN":"少なくともこのクリファ次元は、あなた<color=#ffd34c>たち</color>の同一性を認めています。","ENG":"At the very least, this Qlipha Dimension recognizes the identicalness between you <color=#ffd34c>both</color>.","TWN":"至少在這個逆卡巴拉次元裡，承認<color=#ffd34c>你們</color>的同一性。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇다는 말은…….","JPN":"ということは……","ENG":"Which means...","TWN":"也就是說……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금이야말로, 각본의 마지막 퍼즐 조각을 끼워 넣을 때겠죠.","JPN":"今こそ、パズルの最後のピースをはめて、脚本を完成させる時なのでしょう。","ENG":"Now is the time to place the final puzzle piece of the script.","TWN":"現在，是把最後一塊拼圖嵌入劇本的時候了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 파노라마의 거울 조각이잖아요……?","JPN":"それはパノラマの鏡の破片……？","ENG":"That's a Panorama mirror fragment...?","TWN":"那是……全的碎片吧……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 이건 스완이 이 세계 테라브레인 속에 숨겨둔 마지막 거울 조각.","JPN":"はい。これはスワンがこの世界のテラブレインに隠した最後の鏡の破片です。","ENG":"That's right. This is the final mirror fragment Swan hid within this world's Terrabrain.","TWN":"沒錯。這是史旺藏在這個世界特拉大腦中的最後一塊鏡片。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"동시에 이건 그녀가 당신에게 바치는 <color=#ffd34c>최후의 걸작</color>입니다.","JPN":"同時にこれは、彼女があなたに捧げる<color=#ffd34c>最後の傑作</color>でもあります。","ENG":"At the same time, it is the <color=#ffd34c>final masterpiece</color> she offers to you.","TWN":"同時，也是她獻給你的<color=#ffd34c>最後的傑作</color>。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"최후의 걸작……?","JPN":"最後の傑作……？","ENG":"Final masterpiece...?","TWN":"最後的傑作……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"마왕의 권능을 다루는 건, 아직 익숙하지 않지만.","JPN":"魔王の権能を扱うのはまだ不慣れですが……","ENG":"I'm not fully accustomed to handling a Demon Lord's power yet.","TWN":"雖然我還不太習慣操縱魔王的權能，"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"거울 조각에 담긴 타기리온의 클리파 허수 에너지는 상쇄해 두었습니다.","JPN":"鏡の破片に宿っていたタギリオンのクリファ虚数エネルギーは相殺しておきました。","ENG":"But I've already neutralized the Qlipha Imaginary Energy of Thagirion contained within the fragment.","TWN":"但我已經中和碎片中蘊含的塔基里翁逆卡巴拉虛數能量。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"이걸로 당신은 타기리온의 주박에서 벗어날 수 있겠죠.","JPN":"これであなたはタギリオンの呪縛から解き放たれる。","ENG":"With this, you should be able to break free from Thagirion's binding.","TWN":"這樣一來，你就能擺脫塔基里翁的束縛了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐! 당신……!","JPN":"ちょ、ちょっと！　あなた……！","ENG":"W-wait! You...!","TWN":"喂，等一下！你……！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭔가요? 갑자기 왜 다가오는 건데요……!?","JPN":"何ですか？　何で急に近づいてくるんですか……！？","ENG":"What are you doing? Why are you coming closer all of a sudden...?!","TWN":"幹嘛？你為什麼突然靠過來……！？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"악의는 없지만, 조금은 아플지도 몰라요.","JPN":"悪気はありませんが、少し痛いかもしれません。","ENG":"I don't mean any harm, but it might hurt a little.","TWN":"我沒有惡意，不過可能會有點痛喔。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"일단은 이 조각을 당신에게 찔러 넣는 게, 그녀가 정해둔 조건인 모양이니까.","JPN":"この破片をあなたに突き刺すのが、どうやら彼女が決めた条件のようですから。","ENG":"It seems that stabbing this fragment into you is the condition she set.","TWN":"總之，把這個碎片刺進你體內，似乎是她事先訂下的條件。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_CA_NULL_ON","text":{"KOREA":"세피라의 비틀림으로 탄생한 당신이 그 존재를 유지하기 위해서는 필요한 일이겠죠.","JPN":"セフィラの歪みから生まれたあなたがその存在を保つために必要なことなのでしょう。","ENG":"For someone like you, born from Sephira's distortion, it's probably necessary to maintain your existence.","TWN":"為了維持你這個因塞菲拉的扭曲而誕生的存在，這是必要的吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"조, 조건……?","JPN":"じょ、条件……？","ENG":"C-condition...?","TWN":"條、條件……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"찔러 넣는다니요…? 그 조각을……!?","JPN":"突き刺すですって……？　その破片を……！？","ENG":"Stabbing me...? With that fragment...?!","TWN":"刺進去是什麼意思……？那個碎片……！？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"커흑──────!?","JPN":"くっつ──────！？","ENG":"Gah──────?!","TWN":"咳啊──────！？"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"걱정 마세요, 스완.","JPN":"心配要りません、スワン。","ENG":"Don't worry, Swan.","TWN":"別擔心，史旺。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아마도 그곳에서 당신을 기다리고 있는 사람이 있을 겁니다.","JPN":"そこであなたを待っている人がいるはずです。","ENG":"There's probably someone waiting for you on the other side.","TWN":"大概會有人在那裡等著你。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"기다리고 있는……. 사람이라고……?","JPN":"待っている……人……？","ENG":"Someone... waiting...?","TWN":"等著……我的人……？"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 사람은 바로 당신.","JPN":"その人はあなた自身。","ENG":"That person is you.","TWN":"那個人，就是你自己。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오랜 각본의 저편에서 끝나지 않는 방황을 계속 하고 있는 여인이죠.","JPN":"悠久なる脚本の彼方で、果てしなく彷徨い続けている人です。","ENG":"A woman who has continued wandering endlessly beyond a long script.","TWN":"在漫長劇本的彼岸，仍不斷徬徨的女人。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"끊임없이 또 끊임없이……. 당신은 줄곧 방황해 왔거든요.","JPN":"途方もなく長い間……あなたはずっと彷徨ってきました。","ENG":"Again and again... You've been wandering all this time.","TWN":"一次又一次……你一直都在迷惘。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 부디, 이걸로 당신의 오랜 방황에 방점이 찍히길 바랍니다.","JPN":"だからどうかこれで、あなたの長い旅に終止符を打てることを祈ります。","ENG":"So please, let this finally put a full stop to your long wandering.","TWN":"所以，請務必讓這一刻成為你長久以來徬徨的終止符。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스완 클레어.","JPN":"スワン・クレア。","ENG":"Swan Claire.","TWN":"史旺．克蕾兒。"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 느낌……. 그리고 이 기억은……?","JPN":"この感覚……そしてこの記憶は……？","ENG":"This feeling... and these memories...?","TWN":"這種感覺……還有這段記憶是……？"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아아, 아아아아아아────────────!!","JPN":"ああ、ああああああ────────────！！","ENG":"Ah, AAAAAAAAH────────────!!","TWN":"啊啊，啊啊啊啊啊啊────────────！！"},"stage":{"bg":"OMEN_CHARADE_02","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"크윽, 이 곳은……?","JPN":"くっ、ここは……？","ENG":"Kgh, where am I...?","TWN":"唔，這裡是……？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭔가 기분이 이상해. 분명 처음일 텐데, 꼭 데자뷰처럼…….","JPN":"何か変な気分……初めて来る場所なのに、まるでデジャブのように……","ENG":"Something feels strange. It should be my first time here, but it feels like deja vu...","TWN":"感覺好奇怪。明明是第一次，卻像既視感……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 이 공간은……?","JPN":"いったいこの空間は……？","ENG":"What is this place...?","TWN":"這空間究竟是……？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"이곳은 기억의 극장.","JPN":"ここは記憶の劇場。","ENG":"This is the Theater of Memory.","TWN":"這裡是記憶劇場。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_QM","text":{"KOREA":"제 완전 기억 능력이 클리파 허수 에너지를 통해 재구성된 심상공간이랍니다.","JPN":"私の完全記憶能力がクリファ虚数エネルギーによって再構築された心象空間です。","ENG":"It's a place of imagination reconstructed through Qlipha Imaginary Energy by my perfect memory ability.","TWN":"是我那完全記憶能力，透過逆卡巴拉虛空能量重構的心象空間。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요. 역시 당신은…….","JPN":"……なら、やはりあなたは……","ENG":"I see. And you are...","TWN":"原來如此。果然是你……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로. 그건 무척이나 오래된 다짐.","JPN":"すべては脚本どおりに。それはとても古い誓い。","ENG":"Everything according to the script. A very old vow.","TWN":"一切都按照劇本進行，那是我長久以來的決心。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 이 심상세계에 다다랐다는 건, 최후의 각본이 결실을 맺었다는 뜻이겠죠.","JPN":"あなたがこの心象世界にたどり着いたということは、最後の脚本が実を結んだということでしょう。","ENG":"The fact that you've reached this place of imagination means the final script has borne fruit.","TWN":"你能抵達這個心象世界，也代表最終的劇本已經開花結果了吧。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 대장님께는 빚을 지고 말았네요.","JPN":"ふふ、隊長には借りを作ってしまいましたね。","ENG":"Haha, I ended up owing Commander a debt.","TWN":"呵呵，我可是欠了隊長一個人情呢。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 관리자, 존 스미스 역시 어느 시점에서 제 각본을 눈치채고 있었을 거예요.","JPN":"そして管理者、ジョン・スミスもまた、ある時点から私の脚本に気づいていたはずです。","ENG":"And the Administrator, John Smith, must have realized my script at some point as well.","TWN":"而管理者約翰．史密斯，應該也在某個時間點察覺到我的劇本了。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"끝까지 포기하지 않고, 제 이야기를 따라와 준 훌륭하신 <color=#ffd34c>관객</color>들…….","JPN":"最後まで諦めず、私の物語についてきてくれた立派な<color=#ffd34c>観客</color>の皆さん……","ENG":"To the wonderful <color=#ffd34c>audience</color> who never gave up and followed my story to the end...","TWN":"一路堅持到最後沒有放棄，追隨我故事而來的優秀<color=#ffd34c>觀眾</color>們……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기꺼이 찬사를 보내 드리고 싶네요.","JPN":"本当に素晴らしいです。","ENG":"I would like to offer my heartfelt applause.","TWN":"我由衷想向你們獻上喝采。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이제야 조금 알겠어요.","JPN":"やっと少しわかった気がします。","ENG":"I think I finally understand a little.","TWN":"我現在終於稍微明白了。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 자신을 속여가면서까지 엉터리 연기를 해왔던 건, 바로 지금을 위해서였군요.","JPN":"あなたが自分を騙してまで下手な芝居を続けてきたのは、この瞬間のためだったんですね。","ENG":"You deceived yourself and kept up that sham of a performance all for this moment.","TWN":"你不惜欺騙自己、演出那種拙劣戲碼，全都是為了現在這一刻。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그야 물론이죠. ","JPN":"もちろんです。 ","ENG":"Of course.","TWN":"那當然囉。 "},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 런던 최고의 프리마돈나. 마음만 먹으면 누구든 속일 수 있으니까요. ","JPN":"私はロンドン一のプリマドンナ。その気になれば誰でも騙せますから。 ","ENG":"I am London's greatest prima donna. If I wish, I can deceive anyone.","TWN":"我可是倫敦最頂尖的首席女伶。只要我想，誰都能欺騙。 "},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러나 단 한사람에게는 속마음을 들키고 말았네요.","JPN":"しかしたった一人、私の本音に気づいた人がいましたね。","ENG":"But there was one person who saw through my true feelings.","TWN":"不過，唯獨有一個人，看穿了我的真心。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그야 뻔하잖아요.","JPN":"当たり前じゃないですか。","ENG":"That's obvious.","TWN":"那不是很明顯嗎？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"미래의 제가 그렇게 한심한 여자일 리 없으니까.","JPN":"未来の私がそんなに情けない女であるはずがありませんから。","ENG":"There's no way my future self could be such a pathetic woman.","TWN":"未來的我，不可能是那麼不堪的女人。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"만일 그렇게 된다면, 틀림없이 그럴만한 이유가 있었겠죠.","JPN":"もしそうなるなら、きっとそれ相応の理由があったのでしょう。","ENG":"If that were the case, there must have been a reason.","TWN":"如果真的變成那樣，一定有不得不那麼做的理由吧。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"악을 연기해야만 하는 이유가.","JPN":"悪を演じなければならない理由が。","ENG":"A reason to play the role of evil.","TWN":"必須扮演惡人的理由。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에게 있어서, 이 각본의 궁극적인 목적은 모든 것을 처음으로 되돌리는 것.","JPN":"私にとってこの脚本の究極の目的は、すべてを振り出しに戻すことでした。","ENG":"For me, the ultimate purpose of this script is to return everything to the beginning.","TWN":"對我而言，這份劇本的最終目的，是讓一切回到原點。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그것을 위해서라면, 그 어떤 배역도 받아들이겠다고 각오했으니까요.","JPN":"そのためならどんな役でも受け入れると覚悟しました。","ENG":"And for that, I resolved myself to accept any role, no matter what it may be.","TWN":"為了達成這個目的，我早已下定決心，無論什麼角色都願意接下。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 연기라고 해도 죄를 저지른다면 언젠가 죗값을 치러야 해요.","JPN":"ですがたとえ演技だとしても、罪を犯せばいつかは償わなければいけません。","ENG":"Even if it's just acting, I will have to pay for the sins I committed someday.","TWN":"但就算是演戲，只要犯下罪行，終有一天也得付出代價。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"모든 것이 처음으로 돌아간다고 해도, 그 죄는 사라지지 않죠.","JPN":"すべてが始まりに戻っても、その罪は消えませんから。","ENG":"Even if everything returns to the beginning, those sins won't disappear.","TWN":"即使一切回到原點，那份罪孽也不會消失。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 저는 제가 틀렸다고 생각하지는 않아요.","JPN":"それでも私は、自分が間違っているとは思いません。","ENG":"Even so, I don't think I was wrong.","TWN":"即便如此，我並不認為自己錯了。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저라면 절대 도망치지 않을 테니까요.","JPN":"「私」なら、絶対に逃げたりしませんから。","ENG":"If it were me, I would never run away.","TWN":"如果是我，絕對不會逃避。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설령, 앞으로 무수한 실패를 겪게 된다고 할지라도…….","JPN":"たとえこれから無数の失敗を重ねることになるとしても……","ENG":"Even if I were to face countless failures ahead...","TWN":"哪怕未來要經歷無數失敗……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"설령, 그로 인해, 제 손이 더러워져 불게 물들지라도…….","JPN":"そのせいで、この手が赤く染まるとしても。","ENG":"Even if, because of that, my hands were stained filthy red...","TWN":"哪怕因此雙手會更加骯髒、染上鮮血……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이라면…….","JPN":"あなたなら……","ENG":"If it were you...","TWN":"如果是你……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이라면…….","JPN":"あなたなら……","ENG":"If it were you...","TWN":"如果是你……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 각본 끝에 어떤 결말이 기다리고 있다 하더라도.","JPN":"その脚本の終わりにどんな結末が待っていようと……","ENG":"No matter what ending awaits me at the end of it.","TWN":"無論那份劇本的終點有怎樣的結局在等待著，"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"절대 발버둥을 포기하지 않을 테니까.","JPN":"決して足掻くことをやめないはずですから。","ENG":"You would never give up struggling.","TWN":"你絕對不會放棄掙扎。"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기억하고 계시나요?","JPN":"覚えていますか？","ENG":"Do you remember?","TWN":"你還記得嗎？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"베르디의 라 트라비아타는 초연에 실패하고 말았어요.","JPN":"ヴェルディのラ・トラヴィアータは初演に失敗しました。","ENG":"Verdi's La traviata failed at its premiere.","TWN":"威爾第的《茶花女》，在首演時失敗了。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 지금은 누구나 이름만 들어도 아는 유명한 작품이 되었죠.","JPN":"ですが、今は誰もが知る有名な作品になっています。","ENG":"But now it's a famous work everyone knows by name.","TWN":"但如今卻成了人人耳熟能詳的名作。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이야말로 잊으셨나 보네요?","JPN":"あなたこそ忘れたのですか？","ENG":"Have you forgotten?","TWN":"你該不會忘了吧？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"1885년 밀라노 극장에서 제 첫 데뷔 무대가 라 트라비아타였다는 걸.","JPN":"1885年、ミラノの劇場で行われた私の初舞台がラ・トラヴィアータだったことを。","ENG":"That my very first debut stage was La traviata at a Milan theater in 1885.","TWN":"我1885年在米蘭劇院的首次登台演出，正是《茶花女》。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 잊을 수가 없죠. 그 끔찍한 무대.","JPN":"ふふ、忘れるわけがありません。あの酷い舞台を。","ENG":"Fufu, how could I forget that dreadful stage?","TWN":"呵呵，我怎麼可能忘記那場慘不忍睹的表演。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"웃지 마요. 누구에게나 첫 무대는 엉망이라고요.","JPN":"笑わないでください。誰にでも初舞台は未熟なものなのです。","ENG":"Don't laugh. Everyone's first stage is a mess.","TWN":"別笑了，每個人第一次登台都很糟糕。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 실패가 있었기에, 비로소 런던 최고의 프리마돈나가 될 수 있었어요.","JPN":"でもその失敗があったからこそ、私はロンドン一のプリマドンナになれました。","ENG":"But because of that failure, I was finally able to become London's greatest prima donna.","TWN":"正因為那次失敗，我才能成為倫敦最頂尖的首席女伶。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 당신이 있었기에, 지금의 제가 있죠.","JPN":"そしてあなたがいたから、今の私がいる。","ENG":"And because of you, I am who I am now.","TWN":"而且正因為有你，才有現在的我。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 그걸 부정하지 않아요.","JPN":"私はそれを否定しません。","ENG":"I don't deny that.","TWN":"我不否認這一點。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엄밀히 말하면, 당신은 세피라를 비틀어 만들어낸 제 창작물에 불과해요.","JPN":"厳密に言えば、あなたは私がセフィラを歪ませて作り出した仮初の存在に過ぎません。","ENG":"Strictly speaking, you're nothing more than a creation I made by distorting Sephira.","TWN":"嚴格來說，你不過是我扭曲賽菲拉創造的產物。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"비록 만들어진 캐릭터에 불과하더라도, 마음이 담기면 그 또한 저의 일부예요.","JPN":"作られたキャラクターに過ぎないとしても、心が宿ればそれは私の一部です。","ENG":"Even if I'm just a created character, if my heart is in it, then it's also a part of me.","TWN":"即使只是被創造出來的角色，只要注入感情，那也是我的一部分。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장에서 모든 기억을 인계 받는 순간, 당신은 더는 당신이 아니게 될지도 몰라요.","JPN":"この劇場ですべての記憶を引き継ぐ瞬間、あなたはあなたでなくなるかもしれません。","ENG":"The moment you inherit all memories in this theater, you may no longer be you.","TWN":"在這座劇場，當你繼承所有記憶的瞬間，或許你就不再是你自己了。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 두려워요. 하지만 외면하고 싶지는 않아요.","JPN":"もちろん、怖いです。それでも目を背けたくはありません。","ENG":"Of course, I'm afraid. But I don't want to look away.","TWN":"當然，我會害怕。但我不想逃避。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무지는 죄니까요. 그러니 새로운 무대에서 제가 맡을 배역이 무엇인지 알고 싶어요.","JPN":"無知は罪ですから。だから新たな舞台で私が務める役が何なのか、知りたいのです。","ENG":"Ignorance is a sin. That's why I want to know what role I'll play on the new stage.","TWN":"無知即是罪。所以我想知道在新的舞台，我將扮演什麼樣的角色。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신의 기억이 있다면, 우리는 다른 결말을 맞이할 수 있을 테니까.","JPN":"あなたの記憶があれば、私たちは違う結末を迎えられるでしょうから。","ENG":"If we have your memories, we can reach a different ending.","TWN":"只要擁有你的記憶，我們就能迎來不同的結局。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……훌륭하군요.","JPN":"……見事です。","ENG":"...Splendid.","TWN":"……真了不起。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면, 지금부터 꽤 긴 러닝 타임이 될 겁니다.","JPN":"それでは、今からかなり長い上演となります。","ENG":"Then from here on out, it will be quite a long running time.","TWN":"那麼，接下來將會是一段相當漫長的演出時間。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"부디, 편안한 관람 되시길…….","JPN":"どうぞごゆっくり……","ENG":"Please, enjoy the show.","TWN":"請務必好好享受……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"강철 같은 영혼을 가진 아름다운 여인, 아이린 애들러.","JPN":"鋼のような魂を持つ美しい女性、アイリーン・アドラー。","ENG":"A beautiful woman with a soul of steel, Irene Adler.","TWN":"擁有鋼鐵般靈魂的美麗女性，艾琳．艾德勒。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};